ALTER TABLE `kpi_markets` ADD COLUMN `zipCodes` json;
ALTER TABLE `kpi_markets` ADD COLUMN `isGlobal` tinyint(1) NOT NULL DEFAULT 0;

CREATE TABLE IF NOT EXISTS `kpi_sources` (
  `id` int NOT NULL AUTO_INCREMENT PRIMARY KEY,
  `tenantId` int NOT NULL,
  `name` varchar(100) NOT NULL,
  `kpi_source_type` enum('outbound','inbound') NOT NULL,
  `tracksVolume` tinyint(1) NOT NULL DEFAULT 0,
  `volumeLabel` varchar(100),
  `ghlSourceMapping` varchar(255),
  `isActive` tinyint(1) NOT NULL DEFAULT 1,
  `createdAt` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updatedAt` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  CONSTRAINT `kpi_sources_tenantId_tenants_id_fk` FOREIGN KEY (`tenantId`) REFERENCES `tenants` (`id`)
);

CREATE TABLE IF NOT EXISTS `kpi_spend` (
  `id` int NOT NULL AUTO_INCREMENT PRIMARY KEY,
  `tenantId` int NOT NULL,
  `sourceId` int NOT NULL,
  `marketId` int NOT NULL,
  `month` varchar(7) NOT NULL,
  `amount` int NOT NULL DEFAULT 0,
  `createdAt` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updatedAt` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  CONSTRAINT `kpi_spend_tenantId_tenants_id_fk` FOREIGN KEY (`tenantId`) REFERENCES `tenants` (`id`),
  CONSTRAINT `kpi_spend_sourceId_kpi_sources_id_fk` FOREIGN KEY (`sourceId`) REFERENCES `kpi_sources` (`id`),
  CONSTRAINT `kpi_spend_marketId_kpi_markets_id_fk` FOREIGN KEY (`marketId`) REFERENCES `kpi_markets` (`id`)
);

CREATE TABLE IF NOT EXISTS `kpi_volume` (
  `id` int NOT NULL AUTO_INCREMENT PRIMARY KEY,
  `tenantId` int NOT NULL,
  `sourceId` int NOT NULL,
  `marketId` int NOT NULL,
  `month` varchar(7) NOT NULL,
  `count` int NOT NULL DEFAULT 0,
  `createdAt` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updatedAt` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  CONSTRAINT `kpi_volume_tenantId_tenants_id_fk` FOREIGN KEY (`tenantId`) REFERENCES `tenants` (`id`),
  CONSTRAINT `kpi_volume_sourceId_kpi_sources_id_fk` FOREIGN KEY (`sourceId`) REFERENCES `kpi_sources` (`id`),
  CONSTRAINT `kpi_volume_marketId_kpi_markets_id_fk` FOREIGN KEY (`marketId`) REFERENCES `kpi_markets` (`id`)
);

